import{_ as a,c as i,o,ah as s}from"./chunks/framework.C-x9UAyH.js";const d="/cloud_mod_respons_compartida.png",_=JSON.parse('{"title":"Modelo de Responsabilidad Compartida","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"aws/modelo_responsab_compartida.md","filePath":"aws/modelo_responsab_compartida.md","lastUpdated":1760459112000}'),r={name:"aws/modelo_responsab_compartida.md"};function l(n,e,t,c,p,u){return o(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="modelo-de-responsabilidad-compartida" tabindex="-1">Modelo de Responsabilidad Compartida <a class="header-anchor" href="#modelo-de-responsabilidad-compartida" aria-label="Permalink to &quot;Modelo de Responsabilidad Compartida&quot;">​</a></h1><p>En AWS, la seguridad y conformidad se basan en un modelo de responsabilidad compartida entre AWS y el cliente.</p><h2 id="responsabilidad-de-aws" tabindex="-1">Responsabilidad de AWS <a class="header-anchor" href="#responsabilidad-de-aws" aria-label="Permalink to &quot;Responsabilidad de AWS&quot;">​</a></h2><p>AWS es responsable de:</p><ul><li>Operar, administrar y controlar los componentes del sistema operativo host.</li><li>Gestionar la capa de virtualización.</li><li>Asegurar la infraestructura física en la que funcionan los servicios (data centers, red, hardware, etc.).</li></ul><p>Este enfoque permite aliviar la carga operativa del cliente, ya que AWS se encarga de gran parte de la infraestructura subyacente.</p><h2 id="responsabilidad-del-cliente" tabindex="-1">Responsabilidad del cliente <a class="header-anchor" href="#responsabilidad-del-cliente" aria-label="Permalink to &quot;Responsabilidad del cliente&quot;">​</a></h2><p>El cliente es responsable de:</p><ul><li>Administrar el sistema operativo invitado (actualizaciones, parches de seguridad).</li><li>Gestionar cualquier software de aplicaciones que instale.</li><li>Configurar correctamente el firewall y los grupos de seguridad proporcionados por AWS.</li></ul><h2 id="consideraciones" tabindex="-1">Consideraciones <a class="header-anchor" href="#consideraciones" aria-label="Permalink to &quot;Consideraciones&quot;">​</a></h2><p>Es importante que los clientes:</p><ul><li>Evalúen cuidadosamente los servicios que eligen.</li><li>Comprendan que las responsabilidades varían según el tipo de servicio usado (IaaS, PaaS, SaaS).</li><li>Tengan en cuenta la integración de estos servicios en su entorno de TI.</li><li>Consideren las leyes y regulaciones que aplican a su industria o región.</li></ul><p align="center"><img src="'+d+'" width="800" alt="modelo_responsabilidad_compartida"></p>',13)])])}const b=a(r,[["render",l]]);export{_ as __pageData,b as default};
